import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o as t,c as o,a as n,b as p,d as i,e as c}from"./app-12bdbe33.js";const l={},u=n("p",null,"AWS S3 버킷에 vue로 빌드한 페이지를 정적 웹 사이트로 호스팅할 수 있습니다.",-1),r={href:"https://docs.aws.amazon.com/ko_kr/AmazonS3/latest/userguide/WebsiteHosting.html?icmpid=docs_amazons3_console",target:"_blank",rel:"noopener noreferrer"},d=c(`<p>S3 버킷을 정적 웹사이트로 호스팅하기 위해서는 다음과 같은 설정이 필요합니다.</p><ol><li>퍼블릭 액세스 설정</li><li>버킷 정책 설정</li><li>CORS 설정</li></ol><p>이렇게 버킷을 설정하는 방법을 알아보고 GitHub Actions에서 배포 설정을 자동화 해보겠습니다.</p><h2 id="버킷-만들고-정적-웹-호스팅-활성화" tabindex="-1"><a class="header-anchor" href="#버킷-만들고-정적-웹-호스팅-활성화" aria-hidden="true">#</a> 버킷 만들고 정적 웹 호스팅 활성화</h2><p>AWS S3로 이동해서 버킷만들기를 눌러서 버킷이름을 설정하고 버킷을 생성합니다.<br> 버킷 이름만 설정하고 만들어도 나중에 설정들은 모두 변경할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/cb8e241b-53e4-42fc-b5a9-bb1240671e5e" alt="버킷을 만든 후 모습" tabindex="0" loading="lazy"><figcaption>버킷을 만든 후 모습</figcaption></figure><p>정적 웹페이지를 사용할 버킷을 눌러서 들어간 후 속성 탭으로 들어가서 맨아래 정적 웹 호스팅을 활성화합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/b9837bce-bf0b-4237-a306-0d9a732c82ae" alt="버킷의 속성 탭" tabindex="0" loading="lazy"><figcaption>버킷의 속성 탭</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/ae07f41b-9612-467b-8a91-c400d9694572" alt="비활성화 된 모습" tabindex="0" loading="lazy"><figcaption>비활성화 된 모습</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/c1490418-98d3-4ded-be1a-b3f15f148d65" alt="활성화로 설정하기" tabindex="0" loading="lazy"><figcaption>활성화로 설정하기</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/8666a960-855a-4a96-b324-b7ab11fbabd0" alt="활성화된 모습" tabindex="0" loading="lazy"><figcaption>활성화된 모습</figcaption></figure><h2 id="버킷-권한-설정" tabindex="-1"><a class="header-anchor" href="#버킷-권한-설정" aria-hidden="true">#</a> 버킷 권한 설정</h2><p>이제 버킷의 권한탭으로 이동해서 퍼블릭 액세스로 설정하고 버킷 정책과 CORS 설정이 필요합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2902df4e-4e0e-417f-929a-60daf183a51d" alt="권한 탭으로 이동 해서 퍼블릭 액세스로 바꾸기" tabindex="0" loading="lazy"><figcaption>권한 탭으로 이동 해서 퍼블릭 액세스로 바꾸기</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/a7d3e3ca-46cf-498d-80e3-c64830a05271" alt="ACL 설정도 변경해줍니다" tabindex="0" loading="lazy"><figcaption>ACL 설정도 변경해줍니다</figcaption></figure><h3 id="버킷-정책" tabindex="-1"><a class="header-anchor" href="#버킷-정책" aria-hidden="true">#</a> 버킷 정책</h3><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;Version&quot;</span><span class="token operator">:</span> <span class="token string">&quot;2012-10-17&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;Statement&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token punctuation">{</span>
      <span class="token property">&quot;Sid&quot;</span><span class="token operator">:</span> <span class="token string">&quot;1&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;Effect&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Allow&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;Principal&quot;</span><span class="token operator">:</span> <span class="token string">&quot;*&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;Action&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;s3:GetObject&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;s3:DeleteObject&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token property">&quot;Resource&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
        <span class="token string">&quot;arn:aws:s3:::vue-blog-frontend/*&quot;</span><span class="token punctuation">,</span>
        <span class="token string">&quot;arn:aws:s3:::vue-blog-frontend&quot;</span>
      <span class="token punctuation">]</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="cors-cross-origin-리소스-공유-설정" tabindex="-1"><a class="header-anchor" href="#cors-cross-origin-리소스-공유-설정" aria-hidden="true">#</a> CORS(Cross-origin 리소스 공유) 설정</h3><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">[</span>
  <span class="token punctuation">{</span>
    <span class="token property">&quot;AllowedHeaders&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;*&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token property">&quot;AllowedMethods&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;HEAD&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;GET&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;PUT&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;POST&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;DELETE&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token property">&quot;AllowedOrigins&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
      <span class="token string">&quot;https://server.zamoca.space&quot;</span><span class="token punctuation">,</span>
      <span class="token string">&quot;https://www.zamoca.space&quot;</span>
    <span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token property">&quot;ExposeHeaders&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;Access-Control-Allow-Origin&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token property">&quot;MaxAgeSeconds&quot;</span><span class="token operator">:</span> <span class="token number">3000</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="리포지토리에서-s3에-배포-설정" tabindex="-1"><a class="header-anchor" href="#리포지토리에서-s3에-배포-설정" aria-hidden="true">#</a> 리포지토리에서 S3에 배포 설정</h2><p>리포지토리에서 <code>.github/workflows</code>에 <code>vue-S3.yml</code>파일을 만들고 다음과 같이 설정했습니다.</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">name</span><span class="token punctuation">:</span> Frontend Deploy <span class="token comment"># action 명</span>

<span class="token key atrule">on</span><span class="token punctuation">:</span> <span class="token comment"># 이벤트 트리거</span>
 <span class="token key atrule">push</span><span class="token punctuation">:</span> <span class="token comment"># push event에 반응</span>
  <span class="token key atrule">paths</span><span class="token punctuation">:</span>
   <span class="token punctuation">-</span> <span class="token string">&quot;frontend/**&quot;</span> <span class="token comment"># frontend의 변경이 있을 때</span>
  <span class="token key atrule">branches</span><span class="token punctuation">:</span> <span class="token comment"># github repository의 branch가</span>
   <span class="token punctuation">-</span> main <span class="token comment"># main 일 경우만</span>

<span class="token key atrule">jobs</span><span class="token punctuation">:</span>
 <span class="token key atrule">deploy</span><span class="token punctuation">:</span> <span class="token comment"># GitHub-hosted runners env</span>
  <span class="token key atrule">runs-on</span><span class="token punctuation">:</span> macos<span class="token punctuation">-</span>latest <span class="token comment"># using MacOS</span>

 <span class="token key atrule">defaults</span><span class="token punctuation">:</span>
  <span class="token key atrule">run</span><span class="token punctuation">:</span>
   <span class="token key atrule">working-directory</span><span class="token punctuation">:</span> <span class="token string">&quot;frontend&quot;</span> <span class="token comment"># frontend 폴더에서 실행</span>

 <span class="token key atrule">steps</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">uses</span><span class="token punctuation">:</span> actions/checkout@v3

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Set Node.js 18.x
    <span class="token key atrule">uses</span><span class="token punctuation">:</span> actions/setup<span class="token punctuation">-</span>node@v3
    <span class="token key atrule">with</span><span class="token punctuation">:</span>
   <span class="token key atrule">node-version</span><span class="token punctuation">:</span> 18.x

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Install dependencies
    <span class="token key atrule">run</span><span class="token punctuation">:</span> npm install

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Build page
    <span class="token key atrule">run</span><span class="token punctuation">:</span> npm run build

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Authenticate AWS CLI
    <span class="token key atrule">env</span><span class="token punctuation">:</span>
   <span class="token key atrule">AWS_ACCESS_KEY_ID</span><span class="token punctuation">:</span> $<span class="token punctuation">{</span><span class="token punctuation">{</span> secrets.AWS_ACCESS_KEY_ID <span class="token punctuation">}</span><span class="token punctuation">}</span>
   <span class="token key atrule">AWS_SECRET_ACCESS_KEY</span><span class="token punctuation">:</span> $<span class="token punctuation">{</span><span class="token punctuation">{</span> secrets.AWS_SECRET_ACCESS_KEY <span class="token punctuation">}</span><span class="token punctuation">}</span>
   <span class="token key atrule">AWS_REGION</span><span class="token punctuation">:</span> $<span class="token punctuation">{</span><span class="token punctuation">{</span> secrets.AWS_REGION <span class="token punctuation">}</span><span class="token punctuation">}</span>

    <span class="token key atrule">run</span><span class="token punctuation">:</span> <span class="token punctuation">|</span><span class="token scalar string">
   aws configure set aws_access_key_id $AWS_ACCESS_KEY_ID
   aws configure set aws_secret_access_key $AWS_SECRET_ACCESS_KEY
   aws configure set default.region $AWS_REGION</span>

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> remove <span class="token comment"># 삭제</span>
    <span class="token key atrule">run</span><span class="token punctuation">:</span> <span class="token punctuation">|</span><span class="token scalar string">
   aws s3 rm s3://my-site/assets/ --recursive
   aws s3 rm s3://my-site/blog/ --recursive</span>

  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> deploy <span class="token comment"># 배포</span>
    <span class="token key atrule">run</span><span class="token punctuation">:</span> <span class="token punctuation">|</span><span class="token scalar string">
   aws s3 cp --recursive dist s3://my-site</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="배포-확인" tabindex="-1"><a class="header-anchor" href="#배포-확인" aria-hidden="true">#</a> 배포 확인</h2><figure><img src="https://github.com/Zamoca42/vue-django-blog/assets/96982072/536400d1-9c93-4e3d-845e-53e5222a1c1a" alt="마지막 수정 시간 확인" tabindex="0" loading="lazy"><figcaption>마지막 수정 시간 확인</figcaption></figure><p>S3에서 변경사항이 업데이트 되고있는지 마지막 수정 시간에서 확인할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/34371e10-988a-4c73-b73c-97d93d39c037" alt="블로그 페이지" tabindex="0" loading="lazy"><figcaption>블로그 페이지</figcaption></figure><p>Route53과 CloudFront까지 사용해서 원하는 도메인으로 라우팅한다면 이런 페이지로 보여집니다.</p><h2 id="리포지토리의-actions-확인하기" tabindex="-1"><a class="header-anchor" href="#리포지토리의-actions-확인하기" aria-hidden="true">#</a> 리포지토리의 Actions 확인하기</h2><p>리포지토리의 Actions 탭가서 배포가 잘 진행되고있는지 확인할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/e9a9cb70-1e51-4468-a9cd-159160913b0e" alt="실패했을 때는 :x:가 나옵니다" tabindex="0" loading="lazy"><figcaption>실패했을 때는 ❌가 나옵니다</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/ad181d57-c69b-4fce-b9d7-4bdaa43b76bd" alt="변경사항이 있을때마다 배포가 실행됩니다" tabindex="0" loading="lazy"><figcaption>변경사항이 있을때마다 배포가 실행됩니다</figcaption></figure>`,31);function k(v,m){const s=e("ExternalLinkIcon");return t(),o("div",null,[u,n("ul",null,[n("li",null,[n("a",r,[p("Amazon S3를 사용하여 정적 웹 사이트 호스팅"),i(s)])])]),d])}const h=a(l,[["render",k],["__file","s3-deploy.html.vue"]]);export{h as default};
